
.app-hint {
  padding: 0.85em 1em;
  color: var(--text-muted);
  background: var(--bg-card);
  border: 1px dashed var(--border-subtle);
  border-radius: var(--radius-md);
  overflow-wrap: anywhere;
  font-size: 0.85rem;

  code {
    font-size: 0.9em;
    color: var(--accent-lavender);
    font-family: var(--font-mono);
  }
}
